"""
TDD Stage: reduce_mean
Pass 1: tilize input, reduce SUM along row with 1/W scaler to compute row-wise mean. Output is a column vector.
"""

import pytest
import torch
import ttnn

from ttnn.operations.layer_norm_rm import layer_norm_rm


def pytorch_reference(input_tensor):
    """PyTorch reference for this stage."""
    x = input_tensor
    return x.mean(dim=-1, keepdim=True)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_reduce_mean(device, shape):
    """Verify row-wise mean via tilize + reduce SUM with 1/W scaler."""
    layout = ttnn.ROW_MAJOR_LAYOUT
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input)

    # Shape check
    expected_shape = list(shape[:-1]) + [32]
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison (only column 0 is valid from REDUCE_ROW)
    torch_output = ttnn.to_torch(ttnn_output)
    torch_output = torch_output[:, :, :, 0:1]
    expected = expected[:, :, :, 0:1]
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.02,
        atol=0.1,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
